package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withNormalValues() throws IOException {
        String result = csvFormat.format("value1", "value2", 3);
        assertNotNull(result);
        assertTrue(result.contains("value1"));
        assertTrue(result.contains("value2"));
        assertTrue(result.contains("3"));
    }

    @Test
    void testFormat_withNullValue() throws IOException {
        String result = csvFormat.format("value1", null, "value3");
        assertNotNull(result);
        assertTrue(result.contains("value1"));
        assertTrue(result.contains("value3"));
        // null may be empty or some representation, just check it does not throw
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format();
        assertNotNull(result);
        assertEquals("", result);
    }

    @Test
    void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Create a spy of CSVFormat.DEFAULT by subclassing it via a dynamic proxy or reflection
        CSVFormat spyFormat = spy(csvFormat);

        // Create a mock CSVPrinter that throws IOException on printRecord
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord((Object[]) any());

        // Use reflection to replace the CSVPrinter constructor call inside format method
        // We will replace the CSVPrinter instance inside spyFormat.format by mocking the constructor call
        // Since CSVFormat.format creates a new CSVPrinter(out, this), we need to intercept that

        // To do this, use a helper class to override the format method via reflection
        Method formatMethod = CSVFormat.class.getDeclaredMethod("format", Object[].class);
        formatMethod.setAccessible(true);

        // We will create a subclass of CSVFormat that overrides format to inject our mockPrinter
        CSVFormat customFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteChar(),
                csvFormat.getQuotePolicy(),
                csvFormat.getCommentStart(),
                csvFormat.getEscape(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord()) {
            @Override
            public String format(final Object... values) {
                try {
                    mockPrinter.printRecord(values);
                    return "";
                } catch (IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            customFormat.format("value");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }
}
